            # filter contours by area (adjust based on video size)
            good_contours = []
            for cnt in contours:
                area = cv2.contourArea(cnt)
                if 1000 < area < 50000:  # reasonable range for athlete
                    good_contours.append(cnt)
            if good_contours:
                largest = max(good_contours, key=cv2.contourArea)
                M = cv2.moments(largest)
                if M['m00'] != 0:
                    cx = int(M['m10']/M['m00'])
                    cy = int(M['m01']/M['m00'])
                    valid.append(True)
                else:
                    valid.append(False)
            else:
                valid.append(False)
        else:
            valid.append(False)
        centroid_ys.append(cy)

    cap.release()

    # Smooth centroid values
    def smooth(values, window=5):
        smoothed = []
        for i in range(len(values)):
            start = max(0, i - window//2)
            end = min(len(values), i + window//2 + 1)
            smoothed.append(np.mean(values[start:end]))
        return smoothed

    smoothed = smooth(centroid_ys, window=5)

    # Find largest continuous block of valid detections
    blocks = []
    current = []
    for i, v in enumerate(valid):
        if v:
            current.append(i)
        else:
            if current:
                blocks.append(current)
                current = []
    if current:
        blocks.append(current)
    if not blocks:
        raise RuntimeError('No valid athlete detection in video')
    block = max(blocks, key=len)

    cy_block = [smoothed[i] for i in block]
    min_idx = np.argmin(cy_block)
    min_frame = block[min_idx]

    # Ground level: average of first few frames before jump
    pre_frames = block[:min_idx]
    if pre_frames:
        ground = np.mean([smoothed[i] for i in pre_frames])
    else:
        ground = smoothed[block[0]]

    # Threshold for crossing ground level
    threshold = 10
    # Takeoff: moving backward from minimum
    takeoff_frame = block[0]
    for i in range(min_idx, 0, -1):
        if cy_block[i] > ground - threshold:
            takeoff_frame = block[i]
            break

    # Landing: moving forward from minimum
    landing_frame = block[-1]
    for i in range(min_idx, len(cy_block)):
        if cy_block[i] > ground + threshold:
            landing_frame = block[i]
            break

    return takeoff_frame, landing_frame

def main():
    if len(sys.argv) > 1:
        video_path = sys.argv[1]
    else:
        # default for testing
        video_path = 'example_video.mp4'

    try:
        takeoff, landing = analyze_video(video_path)
    except Exception as e:
